'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { Eye, EyeOff, MessageCircle } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { getUsuariosIT, getEmpleadoByCodigo, type UsuarioIT, type Empleado } from '@/lib/firebase';

interface LoginCardProps {
  onLoginSuccess: (user: UsuarioIT) => void;
  onRequestSupport: (username: string, similarUser: string | null) => void;
}

interface AIValidation {
  match: 'exact' | 'similar' | 'prefix' | 'none';
  matchedUser: string | null;
  similarity: number;
  suggestion: string;
}

function levenshtein(a: string, b: string): number {
  const m = a.length, n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      dp[i][j] = a[i - 1] === b[j - 1]
        ? dp[i - 1][j - 1]
        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }
  return dp[m][n];
}

function similarity(a: string, b: string): number {
  const dist = levenshtein(a.toLowerCase(), b.toLowerCase());
  const maxLen = Math.max(a.length, b.length);
  return maxLen === 0 ? 100 : Math.round((1 - dist / maxLen) * 100);
}

function validateUsernameLocal(value: string, allUsers: { username: string }[]): AIValidation {
  const input = value.toLowerCase().trim();
  const usernames = allUsers.map(u => u.username);

  if (input.length < 3) {
    return { match: 'none', matchedUser: null, similarity: 0, suggestion: 'IA: Por favor ingrese al menos 3 caracteres.' };
  }

  // 1. Exact match?
  const exact = usernames.find(u => u.toLowerCase() === input);
  if (exact) {
    return { match: 'exact', matchedUser: exact, similarity: 100, suggestion: 'IA: Usuario reconocido. Por favor ingrese su PIN.' };
  }

  // 2. Sigue escribiendo? — si es prefijo de algun usuario, esperar sin mostrar error
  const prefixUser = usernames.find(u => u.toLowerCase().startsWith(input));
  if (prefixUser) {
    return { match: 'prefix', matchedUser: prefixUser, similarity: 0, suggestion: `IA: Coincide con "${prefixUser}"... siga escribiendo.` };
  }

  // 3. Similar (error ortografico)
  const scored = usernames
    .map(u => ({ username: u, score: similarity(input, u) }))
    .filter(s => s.score >= 50)
    .sort((a, b) => b.score - a.score);

  if (scored.length > 0 && scored[0].score >= 70) {
    const best = scored[0];
    return { match: 'similar', matchedUser: best.username, similarity: best.score, suggestion: `IA: Quizas quiso decir "${best.username}"? (${best.score}% de coincidencia)` };
  }

  // 4. No encontrado
  return { match: 'none', matchedUser: null, similarity: 0, suggestion: 'IA: Usuario no encontrado en el sistema.' };
}

export function LoginCard({ onLoginSuccess, onRequestSupport }: LoginCardProps) {
  const [username, setUsername] = useState('');
  const [pin, setPin] = useState('');
  const [showPin, setShowPin] = useState(false);
  const [step, setStep] = useState<'username' | 'pin'>('username');
  const [aiMessage, setAiMessage] = useState('IA: Esperando identificación...');
  const [matchedUser, setMatchedUser] = useState<UsuarioIT | null>(null);
  const [similarUser, setSimilarUser] = useState<string | null>(null);
  const [showSupportBtn, setShowSupportBtn] = useState(false);
  const [pinAttempts, setPinAttempts] = useState(0);
  const [allUsers, setAllUsers] = useState<UsuarioIT[]>([]);
  const [employee, setEmployee] = useState<Empleado | null>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const usernameRef = useRef('');

  useEffect(() => {
    async function loadUsers() {
      const users = await getUsuariosIT();
      setAllUsers(users);
    }
    loadUsers();
  }, []);

  useEffect(() => {
    if (matchedUser) {
      getEmpleadoByCodigo(matchedUser.codigo).then(setEmployee);
    } else {
      setEmployee(null);
    }
  }, [matchedUser]);

  const doValidate = useCallback(() => {
    const value = usernameRef.current;
    if (value.length < 3) return;

    const result = validateUsernameLocal(value, allUsers.filter(u => u.activo).map(u => ({ username: u.username })));

    if (result.match === 'exact') {
      const user = allUsers.find(u => u.username.toLowerCase() === result.matchedUser?.toLowerCase());
      if (user) {
        setMatchedUser(user);
        setStep('pin');
        setAiMessage('IA: Usuario reconocido. Por favor ingrese su PIN.');
        setShowSupportBtn(false);
      }
    } else if (result.match === 'prefix') {
      setAiMessage(result.suggestion);
      setShowSupportBtn(false);
    } else if (result.match === 'similar') {
      setSimilarUser(result.matchedUser);
      setShowSupportBtn(true);
      setAiMessage(result.suggestion);
    } else {
      setAiMessage('IA: Usuario no encontrado en el sistema.');
      setShowSupportBtn(true);
    }
  }, [allUsers]);

  const handleValidateUsername = (value: string) => {
    usernameRef.current = value;
    setUsername(value);

    if (debounceRef.current) clearTimeout(debounceRef.current);

    if (value.length < 3) {
      setShowSupportBtn(false);
      setSimilarUser(null);
      setAiMessage('IA: Esperando identificación...');
      return;
    }

    setAiMessage('IA: Analizando...');

    debounceRef.current = setTimeout(doValidate, 400);
  };

  const validatePIN = async (value: string) => {
    setPin(value);

    if (value.length === 6 && matchedUser) {
      if (value === matchedUser.pin) {
        setAiMessage('IA: Acceso concedido. Bienvenido.');
        setTimeout(() => onLoginSuccess(matchedUser), 500);
      } else {
        const newAttempts = pinAttempts + 1;
        setPinAttempts(newAttempts);
        setPin('');

        if (newAttempts >= 3) {
          setAiMessage('IA: Demasiados intentos fallidos. Puede solicitar asistencia de IT.');
          setShowSupportBtn(true);
        } else {
          setAiMessage(`IA: PIN incorrecto. Intento ${newAttempts}/3`);
        }
      }
    }
  };

  const handleSupportRequest = () => {
    onRequestSupport(username, similarUser);
  };

  const resetLogin = () => {
    setStep('username');
    setUsername('');
    setPin('');
    setMatchedUser(null);
    setSimilarUser(null);
    setShowSupportBtn(false);
    setPinAttempts(0);
    setAiMessage('IA: Esperando identificación...');
  };

  return (
    <Card className="w-full max-w-lg border-primary/20 bg-card/95 shadow-[0_0_30px_rgba(0,242,255,0.1)] backdrop-blur-xl">
      <CardContent className="flex items-center gap-6 p-8">
        {/* Avatar / Employee Photo */}
        <div className="flex h-28 w-28 shrink-0 items-center justify-center overflow-hidden rounded-xl border-2 border-border bg-background">
          {matchedUser && employee?.foto ? (
            <Avatar className="h-full w-full rounded-none">
              <AvatarImage src={employee.foto} alt={matchedUser.username} className="h-full w-full object-cover" />
              <AvatarFallback className="rounded-none text-2xl font-bold text-primary">
                {matchedUser.username.charAt(0).toUpperCase()}
              </AvatarFallback>
            </Avatar>
          ) : (
            <MessageCircle className="h-12 w-12 text-primary" />
          )}
        </div>

        {/* Form Section */}
        <div className="flex-1 space-y-4">
          <h2 className="text-xl font-bold tracking-wide text-primary">
            SYSTEM JABM
          </h2>

          {/* AI Message */}
          <div className="flex min-h-12 items-center rounded-lg border border-primary/30 bg-primary/5 p-3 text-sm text-foreground">
            {aiMessage}
          </div>

          {/* Username Input */}
          {step === 'username' && (
            <Input
              type="text"
              placeholder="Usuario"
              value={username}
              onChange={(e) => handleValidateUsername(e.target.value)}
              className="border-border bg-input text-foreground placeholder:text-muted-foreground focus:border-primary"
            />
          )}

          {/* PIN Input */}
          {step === 'pin' && (
            <div className="space-y-3">
              <div className="relative">
                <Input
                  type={showPin ? 'text' : 'password'}
                  placeholder="PIN (6 dígitos)"
                  value={pin}
                  onChange={(e) => validatePIN(e.target.value.replace(/\D/g, '').slice(0, 6))}
                  maxLength={6}
                  inputMode="numeric"
                  className="border-border bg-input pr-10 text-foreground placeholder:text-muted-foreground focus:border-primary"
                />
                <button
                  type="button"
                  onClick={() => setShowPin(!showPin)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-primary"
                >
                  {showPin ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </button>
              </div>
              <button
                onClick={resetLogin}
                className="text-xs text-muted-foreground hover:text-primary hover:underline"
              >
                Cambiar usuario
              </button>
            </div>
          )}

          {/* Support Button */}
          {showSupportBtn && (
            <Button
              onClick={handleSupportRequest}
              className="w-full bg-blue-600 text-white hover:bg-blue-700"
            >
              <MessageCircle className="mr-2 h-4 w-4" />
              Asistencia de IT
            </Button>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

components/chat/support-chat.tsx:
'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { Send, X, Bot, User, Loader2, Clock } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import {
  listenToSupportRequest,
  addMessageToRequest,
  getUsuarioByUsername,
  getEmpleadoByCodigo,
  type SupportRequest,
  type UsuarioIT,
  type Empleado,
} from '@/lib/firebase';
import { routeAIRequest } from '@/lib/ai-router';

interface SupportChatProps {
  requestId: string;
  username: string;
  onClose: () => void;
}

interface AiMessage {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  ts: number;
}

type AiContext = 'greeting' | 'awaiting_intent' | 'awaiting_confirmation' | 'done';

const aiResponses: { pattern: RegExp; reply: string }[] = [
  { pattern: /(hola|buenas|buen[ao]s|saludos)/i, reply: 'Hola! Soy el asistente virtual de IT. En que puedo ayudarte hoy?' },
  { pattern: /(ayuda|soporte|asistencia|problema)/i, reply: 'Claro, estoy aqui para ayudarte. Puedes consultarme sobre:\n- Problemas de acceso\n- Restablecimiento de credenciales\n- Dudas sobre el sistema\n\nDescribe tu situacion y te orientare.' },
  { pattern: /(gracias|ok|vale|perfecto|excelente)/i, reply: 'De nada! Si necesitas ayuda adicional, no dudes en escribirme. Si el problema persiste, un tecnico de IT se comunicara contigo pronto.' },
  { pattern: /(cedula|cedula|\d{3}-\d{6}-\d{4}[A-Z]?)/i, reply: 'Gracias. Ahora, para confirmar tu identidad, podrias decirme cual es tu area de trabajo y tu cargo actual?' },
  { pattern: /(tecnico|humano|persona|agente|escalar)/i, reply: 'Entiendo. Voy a escalar tu caso a un tecnico de IT humano. Ellos revisaran tu solicitud y te atenderan a la brevedad. Mientras tanto, quedate atento a este chat.' },
  { pattern: /(no puedo|no funciona|error|falla|bug)/i, reply: 'Lamento escuchar eso. Describe el error exacto que ves en pantalla y desde cuando ocurre para poder ayudarte mejor.' },
  { pattern: /(acceso|permiso|bloqueado|restringido)/i, reply: 'Parece que tienes un problema de permisos. Puedo ayudarte con tus credenciales de acceso. Que necesitas exactamente, tu usuario o tu contraseña?' },
  { pattern: /(fecha|cumpleaños|feliz|birthday)/i, reply: 'Si necesitas informacion sobre fechas especiales o cumpleaños, puedes consultarlo en el modulo de RRHH del panel.' },
  { pattern: /(foto|fotografia|imagen|subir)/i, reply: 'Para subir o actualizar tu foto de perfil, ve a RRHH > Catalogo, busca tu registro y haz doble clic. Ahi podras cambiar tu foto.' },
];

function getGenericReply(message: string): string | null {
  const lower = message.toLowerCase().trim();
  for (const { pattern, reply } of aiResponses) {
    if (pattern.test(lower)) return reply;
  }
  return null;
}

export function SupportChat({ requestId, username, onClose }: SupportChatProps) {
  const [request, setRequest] = useState<SupportRequest | null>(null);
  const [inputValue, setInputValue] = useState('');
  const [aiMessages, setAiMessages] = useState<AiMessage[]>([]);
  const [aiLoading, setAiLoading] = useState(false);
  const [userData, setUserData] = useState<UsuarioIT | null>(null);
  const [empleadoData, setEmpleadoData] = useState<Empleado | null>(null);
  const [context, setContext] = useState<AiContext>('greeting');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const userDataLoaded = useRef(false);

  useEffect(() => {
    const unsubscribe = listenToSupportRequest(requestId, setRequest);
    return unsubscribe;
  }, [requestId]);

  useEffect(() => {
    if (request?.status === 'ai-active' && !userDataLoaded.current) {
      userDataLoaded.current = true;

      getUsuarioByUsername(username).then(async (u) => {
        if (u) {
          setUserData(u);
          const emp = await getEmpleadoByCodigo(u.codigo);
          setEmpleadoData(emp);
          const name = emp ? `${emp.nombres} ${emp.apellidos}` : u.username;
          const greet = `Hola ${name}! Soy el asistente virtual de IT. He identificado tu cuenta en el sistema.\n\nPuedo ayudarte a recuperar tu usuario o restablecer tu contraseña. Que necesitas exactamente?`;
        setAiMessages(prev => [...prev, { id: 'ai-greeting', role: 'assistant', content: greet, ts: Date.now() }]);
        setContext('awaiting_intent');
        } else {
          const greet = 'Hola! Soy el asistente virtual de IT. No he podido identificar tu usuario en el sistema. Un tecnico de IT revisara tu caso para ayudarte.';
          setAiMessages(prev => [...prev, { id: 'ai-greeting', role: 'assistant', content: greet, ts: Date.now() }]);
          setContext('done');
        }
      });
    }
  }, [request?.status, username]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [request?.messages, aiMessages]);

  const wantsPassword = useCallback((msg: string): boolean => {
    const lower = msg.toLowerCase();
    return /(pin|clave|contraseña|password|credencial|pass|pwd)/i.test(lower)
      && !/(usuario|username|user|id|identidad)/i.test(lower);
  }, []);

  const wantsUsername = useCallback((msg: string): boolean => {
    const lower = msg.toLowerCase();
    return /(usuario|username|user|id|identidad|mi nombre)/i.test(lower)
      && !/(clave|contraseña|password|pin|pass|pwd)/i.test(lower);
  }, []);

  const wantsBoth = useCallback((msg: string): boolean => {
    const lower = msg.toLowerCase();
    const hasCred = /(pin|clave|contraseña|password|pass|pwd)/i.test(lower);
    const hasUser = /(usuario|username|user|id|identidad)/i.test(lower);
    return hasCred && hasUser;
  }, []);

  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const message = inputValue;
    setInputValue('');

    if (request?.status === 'ai-active') {
      const userMsg: AiMessage = { id: Date.now().toString(), role: 'user', content: message, ts: Date.now() };
      setAiMessages(prev => [...prev, userMsg]);
      setAiLoading(true);

      try {
        const result = await routeAIRequest({
          role: 'support',
          message,
          context: {
            userName: username,
            userData: userData || undefined,
            empleadoData: empleadoData || undefined,
          },
        });
        setAiMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'assistant', content: result.content, ts: Date.now() }]);
      } catch {
        setAiMessages(prev => [...prev, { id: (Date.now() + 1).toString(), role: 'assistant', content: 'Lo siento, no pude procesar tu solicitud. Un técnico de IT te ayudará en breve.', ts: Date.now() }]);
        setContext('done');
      }
      setAiLoading(false);
    } else {
      await addMessageToRequest(requestId, {
        sender: 'user',
        text: message,
        ts: Date.now(),
      });
    }
  };

  const getStatusMessage = () => {
    switch (request?.status) {
      case 'pending':
        return 'Esperando que un técnico de IT acepte su solicitud...';
      case 'it-active':
        return 'Conectado con soporte de IT';
      case 'ai-active':
        return 'Asistente de IA verificando su identidad';
      case 'resolved':
        return 'Solicitud resuelta';
      default:
        return 'Conectando...';
    }
  };

  const allMessages = request?.status === 'ai-active'
    ? aiMessages.map((m) => ({
        id: m.id,
        sender: m.role === 'user' ? 'user' : 'ai',
        text: m.content,
        ts: m.ts,
      }))
    : request?.messages || [];

  return (
    <Card className="flex h-[500px] w-full max-w-md flex-col border-primary/20 bg-card/95 shadow-[0_0_30px_rgba(0,242,255,0.1)] backdrop-blur-xl">
      <CardHeader className="flex-row items-center justify-between border-b border-border pb-4">
        <div>
          <CardTitle className="text-lg text-primary">Soporte IT</CardTitle>
          <p className="text-xs text-muted-foreground">{getStatusMessage()}</p>
        </div>
        <Button variant="ghost" size="icon" onClick={onClose}>
          <X className="h-4 w-4" />
        </Button>
      </CardHeader>

      <CardContent className="flex flex-1 flex-col gap-4 overflow-hidden p-4">
        {/* Status Badge */}
        <div className="flex items-center justify-center gap-2 rounded-lg bg-muted p-2 text-sm">
          {request?.status === 'pending' && (
            <>
              <Clock className="h-4 w-4 animate-pulse text-yellow-500" />
              <span className="text-muted-foreground">En espera</span>
            </>
          )}
          {request?.status === 'it-active' && (
            <>
              <User className="h-4 w-4 text-green-500" />
              <span className="text-muted-foreground">IT Conectado</span>
            </>
          )}
          {request?.status === 'ai-active' && (
            <>
              <Bot className="h-4 w-4 text-primary" />
              <span className="text-muted-foreground">IA Activa</span>
            </>
          )}
        </div>

        {/* Messages */}
        <div className="flex-1 space-y-3 overflow-y-auto">
          {allMessages.length === 0 && request?.status === 'pending' && (
            <div className="flex h-full items-center justify-center text-center text-sm text-muted-foreground">
              <div>
                <Loader2 className="mx-auto mb-2 h-8 w-8 animate-spin text-primary" />
                <p>Un técnico de IT atenderá su solicitud en breve.</p>
                <p className="mt-1 text-xs">Usuario: {username}</p>
              </div>
            </div>
          )}

          {allMessages.map((msg, i) => (
            <div
              key={msg.id || i}
              className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div
                className={`max-w-[80%] rounded-lg px-3 py-2 text-sm ${
                  msg.sender === 'user'
                    ? 'bg-primary text-primary-foreground'
                    : msg.sender === 'ai'
                    ? 'bg-secondary text-secondary-foreground'
                    : 'bg-green-600 text-white'
                }`}
              >
                {msg.sender !== 'user' && (
                  <div className="mb-1 flex items-center gap-1 text-xs opacity-70">
                    {msg.sender === 'ai' ? <Bot className="h-3 w-3" /> : <User className="h-3 w-3" />}
                    {msg.sender === 'ai' ? 'Asistente IA' : 'Soporte IT'}
                  </div>
                )}
                {msg.text}
              </div>
            </div>
          ))}

          {aiLoading && (
            <div className="flex justify-start">
              <div className="flex items-center gap-2 rounded-lg bg-secondary px-3 py-2 text-sm text-secondary-foreground">
                <Loader2 className="h-3 w-3 animate-spin" />
                Escribiendo...
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        {request?.status !== 'pending' && request?.status !== 'resolved' && (
          <div className="flex gap-2">
            <Input
