                              <AvatarFallback className="bg-gradient-to-br from-pink-100 to-purple-100 text-pink-700 text-lg">
                                {getInitials(emp)}
                              </AvatarFallback>
                            </Avatar>
                          </div>

                          <div className="flex-1 min-w-0">
