'use client';

import dynamic from 'next/dynamic';
import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { getStoredUser } from '@/lib/auth-store';
import { ArrowLeft, Users, MessageSquare, Bell, Code2 } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import type { SupportRequest, UsuarioIT } from '@/lib/firebase';
import { tienePermiso } from '@/lib/permisos';

const SupportQueue = dynamic(() => import('@/components/it-manager/support-queue').then(m => m.SupportQueue), { ssr: false });

interface TileProps {
  title: string;
  subtitle: string;
  icon: React.ReactNode;
  color: string;
  onClick: () => void;
  badge?: number;
}

function Tile({ title, subtitle, icon, color, onClick, badge }: TileProps) {
  return (
    <button
      onClick={onClick}
      className={`group relative min-h-44 min-w-44 overflow-hidden rounded-3xl border-2 border-primary/40 p-6 text-left transition-all duration-200 hover:scale-105 hover:border-primary hover:shadow-[0_0_40px_rgba(0,242,255,0.3)] ${color}`}
    >
      {badge !== undefined && badge > 0 && (
        <div className="absolute right-3 top-3 flex h-6 w-6 items-center justify-center rounded-full bg-red-500 text-xs font-bold text-white">
          {badge}
        </div>
      )}

      <div className="relative z-10">
        <div className="mb-3 text-4xl text-white/90">{icon}</div>
        <div className="text-lg font-bold text-white">{title}</div>
        <div className="text-sm text-white/70">{subtitle}</div>
      </div>
    </button>
  );
}

export default function ITManagerPage() {
  const router = useRouter();
  const [currentUser, setCurrentUser] = useState<UsuarioIT | null>(null);
  const [view, setView] = useState<'tiles' | 'support'>('tiles');
  const [pendingRequests, setPendingRequests] = useState<SupportRequest[]>([]);

  useEffect(() => {
    const user = getStoredUser();
    if (!user) {
      router.push('/');
      return;
    }
    if (!tienePermiso(user, 'itManager')) {
      router.push('/panel');
      return;
    }
    setCurrentUser(user);
  }, [router]);

  useEffect(() => {
    let unsub: (() => void) | undefined;
    import('@/lib/firebase').then(({ listenToSupportRequests }) => {
      unsub = listenToSupportRequests((requests) => {
        setPendingRequests(requests.filter(r => r.status === 'pending'));
      });
    });
    return () => unsub?.();
  }, []);

  if (!currentUser) return null;

  return (
    <main className="min-h-screen bg-gradient-to-br from-background via-background to-secondary/20 p-8">
      {/* Header */}
      <div className="mb-8 flex items-center gap-4">
        <Button
          variant="outline"
          onClick={() => view === 'tiles' ? router.push('/panel') : setView('tiles')}
          className="border-border"
        >
          <ArrowLeft className="mr-2 h-4 w-4" />
          {view === 'tiles' ? 'Regresar' : 'Volver'}
        </Button>
        <h1 className="text-2xl font-black tracking-wider text-primary">
          IT Manager <span className="text-foreground">(Panel)</span>
        </h1>
      </div>

      {view === 'tiles' && (
        <div className="flex flex-wrap justify-center gap-10">
          <Tile
            title="Usuarios"
            subtitle="Gestión de usuarios"
            icon={<Users className="h-10 w-10" />}
            color="bg-gradient-to-br from-[oklch(0.45_0.15_250)] to-[oklch(0.3_0.12_250)]"
            onClick={() => router.push('/panel/it-manager/usuarios')}
          />

          <Tile
            title="Soporte"
            subtitle="Solicitudes de ayuda"
            icon={<MessageSquare className="h-10 w-10" />}
            color="bg-gradient-to-br from-[oklch(0.5_0.15_170)] to-[oklch(0.35_0.12_170)]"
            onClick={() => setView('support')}
            badge={pendingRequests.length}
          />

          <Tile
            title="Notificaciones"
            subtitle="Alertas del sistema"
            icon={<Bell className="h-10 w-10" />}
            color="bg-gradient-to-br from-[oklch(0.6_0.18_60)] to-[oklch(0.45_0.15_60)]"
            onClick={() => {}}
          />

          <Tile
            title="IDE Visual"
            subtitle="Editor de codigo"
            icon={<Code2 className="h-10 w-10" />}
            color="bg-gradient-to-br from-[oklch(0.55_0.2_280)] to-[oklch(0.4_0.15_280)]"
            onClick={() => router.push('/panel/it-manager/ide')}
          />
        </div>
      )}

      {view === 'support' && (
        <Card className="mx-auto max-w-6xl border-primary/20 bg-card/95">
          <CardHeader>
            <CardTitle className="text-primary">Solicitudes de Soporte</CardTitle>
          </CardHeader>
          <CardContent>
            <SupportQueue />
          </CardContent>
        </Card>
      )}
    </main>
  );
}

components/it-manager/support-queue.tsx:
'use client';

import { useState, useEffect } from 'react';
import { Clock, User, Bot, MessageSquare, Check, X } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import {
  listenToSupportRequests,
  updateSupportRequest,
  type SupportRequest,
} from '@/lib/firebase';
import { ITManagerChat } from './it-manager-chat';

export function SupportQueue() {
  const [requests, setRequests] = useState<SupportRequest[]>([]);
  const [activeChat, setActiveChat] = useState<SupportRequest | null>(null);

  useEffect(() => {
    const unsubscribe = listenToSupportRequests((data) => {
      // Sort by createdAt, newest first
      setRequests([...data].sort((a, b) => b.createdAt - a.createdAt));
    });
    return unsubscribe;
  }, []);

  const handleAccept = async (request: SupportRequest) => {
    await updateSupportRequest(request.id, { status: 'it-active' });
    setActiveChat({ ...request, status: 'it-active' });
  };

  const handlePassToAI = async (request: SupportRequest) => {
    await updateSupportRequest(request.id, { status: 'ai-active' });
  };

  const handleResolve = async (requestId: string) => {
    await updateSupportRequest(requestId, { status: 'resolved' });
    setActiveChat(null);
  };

  const getStatusBadge = (status: SupportRequest['status']) => {
    switch (status) {
      case 'pending':
        return (
          <span className="flex items-center gap-1 rounded-full bg-yellow-500/20 px-2 py-1 text-xs text-yellow-500">
            <Clock className="h-3 w-3" /> Pendiente
          </span>
        );
      case 'it-active':
        return (
          <span className="flex items-center gap-1 rounded-full bg-green-500/20 px-2 py-1 text-xs text-green-500">
            <User className="h-3 w-3" /> IT Activo
          </span>
        );
      case 'ai-active':
        return (
          <span className="flex items-center gap-1 rounded-full bg-primary/20 px-2 py-1 text-xs text-primary">
            <Bot className="h-3 w-3" /> IA Activa
          </span>
        );
      case 'resolved':
        return (
          <span className="flex items-center gap-1 rounded-full bg-muted px-2 py-1 text-xs text-muted-foreground">
            <Check className="h-3 w-3" /> Resuelto
          </span>
        );
    }
  };

  if (activeChat) {
    return (
      <ITManagerChat
        request={activeChat}
        onClose={() => setActiveChat(null)}
        onResolve={() => handleResolve(activeChat.id)}
      />
    );
  }

  const pendingRequests = requests.filter(r => r.status === 'pending');
  const activeRequests = requests.filter(r => r.status === 'it-active' || r.status === 'ai-active');
  const resolvedRequests = requests.filter(r => r.status === 'resolved');

  return (
    <div className="space-y-6">
      {/* Pending Requests */}
      {pendingRequests.length > 0 && (
        <div>
          <h3 className="mb-3 flex items-center gap-2 text-sm font-semibold text-yellow-500">
            <Clock className="h-4 w-4" />
            Solicitudes Pendientes ({pendingRequests.length})
          </h3>
          <div className="space-y-3">
            {pendingRequests.map((request) => (
              <Card key={request.id} className="border-yellow-500/30 bg-yellow-500/5">
                <CardContent className="flex items-center justify-between p-4">
                  <div className="flex items-center gap-4">
                    <div className="flex h-10 w-10 items-center justify-center rounded-full bg-yellow-500/20">
                      <MessageSquare className="h-5 w-5 text-yellow-500" />
                    </div>
                    <div>
                      <p className="font-medium text-foreground">{request.username}</p>
                      <p className="text-xs text-muted-foreground">
                        {new Date(request.createdAt).toLocaleString('es')}
                      </p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <Button
                      size="sm"
                      onClick={() => handleAccept(request)}
                      className="bg-green-600 text-white hover:bg-green-700"
                    >
                      <Check className="mr-1 h-4 w-4" />
                      Aceptar
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => handlePassToAI(request)}
                      className="border-primary text-primary hover:bg-primary hover:text-primary-foreground"
                    >
                      <Bot className="mr-1 h-4 w-4" />
                      Pasar a IA
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </div>
      )}

      {/* Active Requests */}
      {activeRequests.length > 0 && (
        <div>
          <h3 className="mb-3 flex items-center gap-2 text-sm font-semibold text-green-500">
            <User className="h-4 w-4" />
            En Proceso ({activeRequests.length})
          </h3>
          <div className="space-y-3">
            {activeRequests.map((request) => (
              <Card key={request.id} className="border-border bg-card">
                <CardContent className="flex items-center justify-between p-4">
                  <div className="flex items-center gap-4">
                    <div className="flex h-10 w-10 items-center justify-center rounded-full bg-muted">
                      {request.status === 'ai-active' ? (
                        <Bot className="h-5 w-5 text-primary" />
                      ) : (
                        <User className="h-5 w-5 text-green-500" />
                      )}
                    </div>
                    <div>
                      <p className="font-medium text-foreground">{request.username}</p>
                      <p className="text-xs text-muted-foreground">
                        {new Date(request.createdAt).toLocaleString('es')}
                      </p>
                    </div>
                    {getStatusBadge(request.status)}
                  </div>
                  <div className="flex gap-2">
                    {request.status === 'it-active' && (
                      <Button
                        size="sm"
                        onClick={() => setActiveChat(request)}
                        className="bg-primary text-primary-foreground hover:bg-primary/90"
                      >
                        <MessageSquare className="mr-1 h-4 w-4" />
                        Ver Chat
                      </Button>
                    )}
                    <Button
                      size="sm"
                      variant="outline"
                      onClick={() => handleResolve(request.id)}
                    >
                      <X className="mr-1 h-4 w-4" />
                      Cerrar
                    </Button>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        </div>
      )}

      {/* Resolved Requests */}
      {resolvedRequests.length > 0 && (
        <div>
          <h3 className="mb-3 flex items-center gap-2 text-sm font-semibold text-muted-foreground">
            <Check className="h-4 w-4" />
            Resueltos ({resolvedRequests.length})
          </h3>
          <div className="space-y-2">
            {resolvedRequests.slice(0, 5).map((request) => (
              <div
                key={request.id}
                className="flex items-center justify-between rounded-lg bg-muted/30 p-3 text-sm"
              >
                <span className="text-muted-foreground">{request.username}</span>
                <span className="text-xs text-muted-foreground">
                  {new Date(request.createdAt).toLocaleString('es')}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {requests.length === 0 && (
        <div className="py-12 text-center text-muted-foreground">
          <MessageSquare className="mx-auto mb-3 h-12 w-12 opacity-30" />
          <p>No hay solicitudes de soporte</p>
        </div>
      )}
    </div>
  );
}

components/it-manager/it-manager-chat.ts:
'use client';

import { useState, useEffect, useRef } from 'react';
import { Send, X, User, Check, Bot } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  listenToSupportRequest,
  addMessageToRequest,
  updateSupportRequest,
  getEmpleadoByCodigo,
  getUsuarioByUsername,
  type SupportRequest,
  type Empleado,
} from '@/lib/firebase';
import { ValidationPanel } from './validation-panel';

interface ITManagerChatProps {
  request: SupportRequest;
  onClose: () => void;
  onResolve: () => void;
}

export function ITManagerChat({ request, onClose, onResolve }: ITManagerChatProps) {
  const [currentRequest, setCurrentRequest] = useState<SupportRequest>(request);
  const [inputValue, setInputValue] = useState('');
  const [empleadoData, setEmpleadoData] = useState<Empleado | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const unsubscribe = listenToSupportRequest(request.id, (data) => {
      if (data) setCurrentRequest(data);
    });
    return unsubscribe;
  }, [request.id]);

  useEffect(() => {
    // Try to find employee data for the user
    async function loadEmpleado() {
      const usuario = await getUsuarioByUsername(request.username);
      if (usuario) {
        const empleado = await getEmpleadoByCodigo(usuario.codigo);
        setEmpleadoData(empleado);
      }
    }
    loadEmpleado();
  }, [request.username]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentRequest.messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    await addMessageToRequest(request.id, {
      sender: 'it',
      text: inputValue,
      ts: Date.now(),
    });

    setInputValue('');
  };

  const handlePassToAI = async () => {
    await updateSupportRequest(request.id, { status: 'ai-active' });
    onClose();
  };

  const messages = currentRequest.messages || [];

  return (
    <div className="flex gap-4">
      {/* Chat Section */}
      <div className="flex min-w-0 flex-1 flex-col rounded-xl border border-border bg-card">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-border p-4">
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-full bg-primary/20">
              <User className="h-5 w-5 text-primary" />
            </div>
            <div>
              <p className="font-medium text-foreground">{request.username}</p>
              <p className="text-xs text-muted-foreground">
                {empleadoData ? `${empleadoData.nombres} ${empleadoData.apellidos} - ${empleadoData.area}` : 'Usuario no verificado'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <Button
              size="sm"
              variant="outline"
              onClick={handlePassToAI}
              className="border-primary text-primary hover:bg-primary hover:text-primary-foreground"
            >
              <Bot className="mr-1 h-4 w-4" />
              Pasar a IA
            </Button>
            <Button
              size="sm"
              onClick={onResolve}
              className="bg-green-600 text-white hover:bg-green-700"
            >
              <Check className="mr-1 h-4 w-4" />
              Resolver
            </Button>
            <Button size="sm" variant="ghost" onClick={onClose}>
              <X className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {/* Employee Info */}
        {empleadoData && (
          <div className="border-b border-border bg-muted/30 p-3 text-xs">
            <div className="grid grid-cols-2 gap-2 text-muted-foreground">
              <div><span className="font-medium">Cedula:</span> {empleadoData.cedula}</div>
              <div><span className="font-medium">Area:</span> {empleadoData.area}</div>
              <div><span className="font-medium">Cargo:</span> {empleadoData.cargo}</div>
              <div><span className="font-medium">Fecha Nac:</span> {empleadoData.fechaNac}</div>
            </div>
          </div>
        )}

        {/* Messages */}
        <div className="flex-1 space-y-3 overflow-y-auto p-4" style={{ maxHeight: '400px' }}>
          {messages.map((msg, i) => (
            <div
              key={msg.id || i}
              className={`flex ${msg.sender === 'it' ? 'justify-end' : 'justify-start'}`}
            >
              <div
                className={`max-w-[80%] rounded-lg px-3 py-2 text-sm ${
                  msg.sender === 'user'
                    ? 'bg-secondary text-secondary-foreground'
                    : msg.sender === 'it'
                    ? 'bg-green-600 text-white'
                    : 'bg-primary text-primary-foreground'
                }`}
              >
                {msg.sender !== 'it' && (
                  <div className="mb-1 flex items-center gap-1 text-xs opacity-70">
                    {msg.sender === 'ai' ? <Bot className="h-3 w-3" /> : <User className="h-3 w-3" />}
                    {msg.sender === 'ai' ? 'IA' : 'Usuario'}
                  </div>
                )}
                {msg.text}
              </div>
            </div>
          ))}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <div className="flex gap-2 border-t border-border p-4">
          <Input
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
            placeholder="Escribir mensaje..."
            className="flex-1 border-border bg-input"
          />
          <Button
            onClick={handleSendMessage}
            className="bg-green-600 text-white hover:bg-green-700"
          >
            <Send className="h-4 w-4" />
          </Button>
        </div>
      </div>

      {/* Validation Panel */}
      <ValidationPanel />
    </div>
  );
}

app/panel/it-manager/usuarios/page.tsx:
'use client';

import dynamic from 'next/dynamic';
import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { getStoredUser } from '@/lib/auth-store';
import { ArrowLeft, Plus, Search, Edit, Trash2, Key, RefreshCw } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import type { UsuarioIT, Empleado } from '@/lib/firebase';
import { tienePermiso, getAllPermisoKeys } from '@/lib/permisos';

const UserFormModal = dynamic(() => import('@/components/it-manager/user-form-modal').then(m => m.UserFormModal), { ssr: false });

export default function UsuariosPage() {
  const router = useRouter();
  const [usuarios, setUsuarios] = useState<UsuarioIT[]>([]);
  const [empleados, setEmpleados] = useState<Empleado[]>([]);
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<UsuarioIT | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const user = getStoredUser();
    if (!user) {
      router.push('/');
      return;
    }
    if (!tienePermiso(user, 'itManager')) {
      router.push('/panel');
      return;
    }

    let unsub1: () => void;
    let unsub2: () => void;

    import('@/lib/firebase').then(({ onValue, ref, db }) => {
      unsub1 = onValue(ref(db, 'usuarios-it'), (snap: any) => {
        const raw = snap.val();
        setUsuarios(raw ? Object.values(raw) : []);
      });
      unsub2 = onValue(ref(db, 'empleados'), (snap: any) => {
        const raw = snap.val();
        setEmpleados(raw ? Object.values(raw) : []);
        setLoading(false);
      });
    });

    return () => { unsub1?.(); unsub2?.(); };
  }, [router]);

  const handleDelete = async (codigo: string) => {
    if (confirm('Esta seguro de eliminar este usuario?')) {
      const { deleteUsuarioIT } = await import('@/lib/firebase');
      await deleteUsuarioIT(codigo);
    }
  };

  const handleResetPIN = async (usuario: UsuarioIT) => {
    const { generarPIN, saveUsuarioIT } = await import('@/lib/firebase');
    const newPin = generarPIN(usuario.codigo);
    await saveUsuarioIT(usuario.codigo, { ...usuario, pin: newPin });
    alert(`PIN actualizado para ${usuario.username}: ${newPin}`);
  };

  const handleToggleActive = async (usuario: UsuarioIT) => {
    const { saveUsuarioIT } = await import('@/lib/firebase');
    await saveUsuarioIT(usuario.codigo, { ...usuario, activo: !usuario.activo });
  };

  const handleOpenCreate = () => {
    setEditingUser(null);
    setIsModalOpen(true);
  };

  const handleOpenEdit = (usuario: UsuarioIT) => {
    setEditingUser(usuario);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingUser(null);
  };

  const filteredUsuarios = usuarios.filter((u) =>
    u.username.toLowerCase().includes(search.toLowerCase()) ||
    u.codigo.includes(search)
  );

  // Get empleado for a user
  const getEmpleado = (codigo: string) => {
    return empleados.find((e) => e.code === codigo);
  };

  // Get empleado name for a user
  const getEmpleadoName = (codigo: string) => {
    const emp = getEmpleado(codigo);
    return emp ? `${emp.nombres} ${emp.apellidos}` : 'N/A';
  };

  // Get initials for avatar fallback
  const getInitials = (codigo: string) => {
    const emp = getEmpleado(codigo);
    if (!emp) return 'US';
    const n = emp.nombres?.charAt(0) || '';
    const a = emp.apellidos?.charAt(0) || '';
    return (n + a).toUpperCase() || 'US';
  };

  return (
    <main className="min-h-screen bg-gradient-to-br from-background via-background to-secondary/20 p-8">
      {/* Header */}
      <div className="mb-8 flex items-center gap-4">
        <Button
          variant="outline"
          onClick={() => router.push('/panel/it-manager')}
          className="border-border"
        >
          <ArrowLeft className="mr-2 h-4 w-4" />
          Volver
        </Button>
        <h1 className="text-2xl font-black tracking-wider text-primary">
          Gestión de Usuarios
        </h1>
      </div>

      <Card className="mx-auto max-w-5xl border-primary/20 bg-card/95">
        <CardHeader className="flex-row items-center justify-between">
          <CardTitle className="text-primary">Usuarios del Sistema</CardTitle>
          <div className="flex items-center gap-3">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder="Buscar..."
                className="w-64 border-border bg-input pl-9"
              />
            </div>
            <Button onClick={handleOpenCreate} className="bg-primary text-primary-foreground">
              <Plus className="mr-2 h-4 w-4" />
              Nuevo Usuario
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="flex items-center justify-center py-12">
              <RefreshCw className="h-8 w-8 animate-spin text-primary" />
            </div>
          ) : filteredUsuarios.length === 0 ? (
            <div className="py-12 text-center text-muted-foreground">
              No hay usuarios registrados
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b border-border bg-muted/30 text-left text-xs uppercase tracking-wider text-muted-foreground">
                    <th className="p-3">Foto</th>
                    <th className="p-3">Codigo</th>
                    <th className="p-3">Usuario</th>
                    <th className="p-3">Empleado</th>
                    <th className="p-3">Rol / Permisos</th>
                    <th className="p-3">Estado</th>
                    <th className="p-3">Acciones</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredUsuarios.map((usuario) => (
                    <tr
                      key={usuario.codigo}
                      className="border-b border-border/50 hover:bg-muted/20"
                    >
                      <td className="p-3">
                        <Avatar className="h-10 w-10 border-2 border-primary/30">
                          <AvatarImage 
                            src={getEmpleado(usuario.codigo)?.foto} 
                            alt={getEmpleadoName(usuario.codigo)} 
                          />
                          <AvatarFallback className="bg-primary/20 text-primary text-sm">
                            {getInitials(usuario.codigo)}
                          </AvatarFallback>
                        </Avatar>
                      </td>
                      <td className="p-3">
                        <span className="rounded bg-primary/20 px-2 py-1 font-mono text-xs text-primary">
                          {usuario.codigo}
                        </span>
                      </td>
                      <td className="p-3 font-medium text-foreground">{usuario.username}</td>
                      <td className="p-3 text-muted-foreground">{getEmpleadoName(usuario.codigo)}</td>
                      <td className="p-3">
                        {usuario.permisos?.itManager ? (
                          <span className="rounded bg-green-500/20 px-2 py-1 text-xs text-green-400 font-medium">
                            IT Manager
                          </span>
                        ) : (
                          <div className="flex flex-wrap gap-1">
                            {usuario.permisos && (() => {
                              const granted = Object.entries(usuario.permisos).filter(([, v]) => v).length;
                              return (
                                <span className="rounded bg-primary/10 px-2 py-1 text-xs text-primary">
                                  {granted} permisos
                                </span>
                              );
                            })()}
                            {!usuario.permisos && (
                              <span className={`rounded px-2 py-1 text-xs ${
                                usuario.rol === 'admin'
                                  ? 'bg-red-500/20 text-red-400'
                                  : usuario.rol === 'it-manager'
                                  ? 'bg-green-500/20 text-green-400'
                                  : 'bg-muted text-muted-foreground'
                              }`}>
                                {usuario.rol}
                              </span>
                            )}
                          </div>
                        )}
                      </td>
                      <td className="p-3">
                        <button
                          onClick={() => handleToggleActive(usuario)}
                          className={`rounded px-2 py-1 text-xs transition-colors ${
                            usuario.activo
                              ? 'bg-green-500/20 text-green-400 hover:bg-green-500/30'
                              : 'bg-red-500/20 text-red-400 hover:bg-red-500/30'
                          }`}
                        >
                          {usuario.activo ? 'Activo' : 'Inactivo'}
                        </button>
                      </td>
                      <td className="p-3">
                        <div className="flex items-center gap-1">
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => handleOpenEdit(usuario)}
                            className="h-8 w-8 p-0 text-primary hover:bg-primary/20"
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => handleResetPIN(usuario)}
                            className="h-8 w-8 p-0 text-yellow-500 hover:bg-yellow-500/20"
                            title="Resetear PIN"
                          >
                            <Key className="h-4 w-4" />
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => handleDelete(usuario.codigo)}
                            className="h-8 w-8 p-0 text-destructive hover:bg-destructive/20"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Modal */}
      {isModalOpen && (
        <UserFormModal
          empleados={empleados}
          existingUser={editingUser}
          onClose={handleCloseModal}
        />
      )}
    </main>
  );
}

components/it-manager/user-form-modal.ts:
'use client';

import { useState, useEffect } from 'react';
import { X, Search, User, Loader2, ChevronDown, ChevronRight, Shield } from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { cn } from '@/lib/utils';
import {
  saveUsuarioIT,
  generarUsername,
  generarPIN,
  getUsuariosIT,
  type UsuarioIT,
  type Empleado,
} from '@/lib/firebase';
import {
  ARBOL_PERMISOS,
  type PermisoItem,
  type PermisosMap,
  permisosPorDefecto,
  todosPermisos,
  getChildrenKeys,
  hasDescendants,
} from '@/lib/permisos';

interface UserFormModalProps {
  empleados: Empleado[];
  existingUser: UsuarioIT | null;
  onClose: () => void;
}

function PermisoCheckbox({
  item,
  permisos,
  onChange,
  parentKey,
  depth = 0,
}: {
  item: PermisoItem;
  permisos: PermisosMap;
  onChange: (key: string, value: boolean) => void;
  parentKey?: string;
  depth?: number;
}) {
  const [expanded, setExpanded] = useState(true);
  const hasChildren = !!item.children && item.children.length > 0;
  const childKeys = hasChildren ? (item.children || []).map(c => c.key) : [];
  const allChildrenChecked = childKeys.length > 0 && childKeys.every(k => permisos[k] === true);
  const someChildrenChecked = childKeys.some(k => permisos[k] === true);
  const isChecked = hasChildren ? allChildrenChecked : permisos[item.key] === true;
  const isIndeterminate = hasChildren && !allChildrenChecked && someChildrenChecked;
  const isITManager = item.key === 'itManager';

  const handleChange = () => {
    if (hasChildren) {
      const newVal = !allChildrenChecked;
      // Toggle all children
      for (const ck of childKeys) {
        onChange(ck, newVal);
      }
      // If toggling a section parent (rrhh, qa), also toggle the section key
      if (childKeys.length > 0) {
        onChange(item.key, newVal);
      }
    } else {
      onChange(item.key, !isChecked);
    }
    // If IT Manager, toggle everything
    if (isITManager) {
      const newVal = !permisos.itManager;
      toggleAll(newVal);
    }
  };

  const toggleAll = (val: boolean) => {
    const setAll = (list: PermisoItem[]) => {
      for (const i of list) {
        onChange(i.key, val);
        if (i.children) setAll(i.children);
      }
    };
    setAll(ARBOL_PERMISOS);
  };

  return (
    <div>
      <label
        className={cn(
          'flex items-center gap-2 py-1.5 px-1 rounded cursor-pointer hover:bg-muted/30 transition-colors',
          depth === 0 && 'font-medium',
          depth === 1 && 'pl-6 text-sm',
          depth === 2 && 'pl-10 text-sm text-muted-foreground',
        )}
      >
        {hasChildren ? (
          <button
            type="button"
            onClick={(e) => { e.stopPropagation(); setExpanded(!expanded); }}
            className="h-5 w-5 flex items-center justify-center shrink-0"
          >
            {expanded ? <ChevronDown className="h-3.5 w-3.5 text-muted-foreground" /> : <ChevronRight className="h-3.5 w-3.5 text-muted-foreground" />}
          </button>
        ) : (
          <div className="h-5 w-5 shrink-0" />
        )}
        <input
          type="checkbox"
          checked={isChecked}
          ref={(el) => { if (el) el.indeterminate = isIndeterminate; }}
          onChange={handleChange}
          disabled={permisos.itManager && !isITManager}
          className={cn(
            'rounded border-border h-4 w-4 shrink-0',
            isITManager && 'text-primary border-primary',
          )}
        />
        {isITManager && <Shield className="h-4 w-4 text-primary shrink-0" />}
        <span className={cn(isITManager && 'text-primary font-semibold')}>
          {item.label}
        </span>
      </label>
      {hasChildren && expanded && (
        <div className="ml-3 border-l border-border/50 pl-2">
          {item.children!.map(child => (
            <PermisoCheckbox
              key={child.key}
              item={child}
              permisos={permisos}
              onChange={onChange}
              parentKey={item.key}
              depth={depth + 1}
            />
          ))}
        </div>
      )}
    </div>
  );
}

export function UserFormModal({ empleados, existingUser, onClose }: UserFormModalProps) {
  const [codigoSearch, setCodigoSearch] = useState('');
  const [selectedEmpleado, setSelectedEmpleado] = useState<Empleado | null>(null);
  const [username, setUsername] = useState('');
  const [pin, setPin] = useState('');
  const [permisos, setPermisos] = useState<PermisosMap>(() => permisosPorDefecto());
  const [preguntaSecreta, setPreguntaSecreta] = useState('');
  const [respuestaSecreta, setRespuestaSecreta] = useState('');
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [activeTab, setActiveTab] = useState<'info' | 'permisos'>('info');

  useEffect(() => {
    if (existingUser) {
      setCodigoSearch(existingUser.codigo);
      setUsername(existingUser.username);
      setPin(existingUser.pin);
      setPermisos(existingUser.permisos || permisosPorDefecto());
      setPreguntaSecreta(existingUser.preguntaSecreta?.question || '');
      setRespuestaSecreta(existingUser.preguntaSecreta?.answer || '');

      const emp = empleados.find(e => e.code === existingUser.codigo);
      if (emp) setSelectedEmpleado(emp);
    }
  }, [existingUser, empleados]);

  const handlePermisoChange = (key: string, value: boolean) => {
    setPermisos(prev => ({ ...prev, [key]: value }));
  };

  const handleSearchEmpleado = () => {
    const emp = empleados.find(e => e.code === codigoSearch);
    if (emp) {
      setSelectedEmpleado(emp);
      const generatedUsername = generarUsername(emp);
      setUsername(generatedUsername);
      if (!existingUser) {
        setPin(generarPIN(codigoSearch));
      }
      setError('');
    } else {
      setSelectedEmpleado(null);
      setUsername('');
      setError('Codigo de empleado no encontrado');
    }
  };

  const handleSave = async () => {
    try {
      if (!selectedEmpleado) {
        setError('Debe seleccionar un empleado');
        return;
      }
      if (!username.trim()) {
        setError('El nombre de usuario es requerido');
        return;
      }
      if (!pin || pin.length < 6) {
        setError('El PIN debe tener al menos 6 digitos');
        return;
      }

      if (!existingUser) {
        const existingUsers = await getUsuariosIT();
        if (existingUsers.some(u => u.username.toLowerCase() === username.toLowerCase())) {
          setError('Este nombre de usuario ya existe');
          return;
        }
      }

      setSaving(true);
      setError('');

      const rol: 'admin' | 'user' | 'it-manager' = permisos.itManager ? 'it-manager' : 'user';

      const usuario: UsuarioIT = {
        codigo: selectedEmpleado.code,
        username: username.trim().toLowerCase(),
        pin,
        rol,
        permisos,
        activo: existingUser ? existingUser.activo : true,
        createdAt: existingUser?.createdAt || new Date().toISOString(),
        ...(preguntaSecreta && respuestaSecreta
          ? { preguntaSecreta: { question: preguntaSecreta, answer: respuestaSecreta } }
          : {}),
      };

      const success = await saveUsuarioIT(selectedEmpleado.code, usuario);
      setSaving(false);

      if (success) {
        onClose();
      } else {
        setError('Error al guardar el usuario. Revisa la consola para mas detalles.');
      }
    } catch (e) {
      console.error('Error saving user:', e);
      setSaving(false);
      setError('Error inesperado: ' + (e instanceof Error ? e.message : 'Error desconocido'));
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSearchEmpleado();
