      { id: 'table', name: 'Table', type: 'component', path: 'components/ui/table.tsx' },
      { id: 'tabs', name: 'Tabs', type: 'component', path: 'components/ui/tabs.tsx' },
      { id: 'select', name: 'Select', type: 'component', path: 'components/ui/select.tsx' },
      { id: 'checkbox', name: 'Checkbox', type: 'component', path: 'components/ui/checkbox.tsx' },
      { id: 'switch', name: 'Switch', type: 'component', path: 'components/ui/switch.tsx' },
      { id: 'avatar', name: 'Avatar', type: 'component', path: 'components/ui/avatar.tsx' },
      { id: 'badge', name: 'Badge', type: 'component', path: 'components/ui/badge.tsx' },
      { id: 'context-menu', name: 'ContextMenu', type: 'component', path: 'components/ui/context-menu.tsx' },
    ],
  },
];

const iconMap: Record<string, React.ElementType> = {
  folder: FolderOpen, component: Box, page: Layout, api: Settings, hook: FileCode, util: FileCode,
};

function getIcon(type: TreeNode['type']) {
  return iconMap[type] || FileCode;
}

function getIconColor(type: TreeNode['type']) {
  switch (type) {
    case 'folder': return 'text-yellow-500';
    case 'page': return 'text-blue-400';
    case 'component': return 'text-green-400';
    case 'api': return 'text-orange-400';
    default: return 'text-muted-foreground';
  }
}

// Recursive helpers
function findParent(nodes: TreeNode[], childId: string): TreeNode[] | null {
  for (const n of nodes) {
    if (n.children?.some(c => c.id === childId)) return n.children;
    if (n.children) {
      const found = findParent(n.children, childId);
      if (found) return found;
    }
  }
  return null;
}

function removeNode(nodes: TreeNode[], id: string): boolean {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) { nodes.splice(i, 1); return true; }
    if (nodes[i].children && removeNode(nodes[i].children!, id)) return true;
  }
  return false;
}

let _nextId = 1000;
function genId() { return `n${_nextId++}`; }

interface TreeItemProps {
  node: TreeNode;
  level: number;
  onSelect: (node: TreeNode) => void;
  selectedId?: string;
  onRename: (node: TreeNode) => void;
  onAddChild: (parent: TreeNode) => void;
  onDelete: (node: TreeNode) => void;
  tree: TreeNode[];
  setTree: (t: TreeNode[]) => void;
}

function TreeItem({ node, level, onSelect, selectedId, onRename, onAddChild, onDelete }: TreeItemProps) {
  const [isExpanded, setIsExpanded] = useState(level < 1);
  const hasChildren = node.children && node.children.length > 0;
  const Icon = getIcon(node.type);
  const isSelected = selectedId === node.id;

  const handleClick = () => {
    if (hasChildren) setIsExpanded(!isExpanded);
    if (node.path || node.type === 'folder') onSelect(node);
  };

  return (
    <ContextMenu>
      <ContextMenuTrigger>
        <div
          onClick={handleClick}
          className={cn(
            'flex items-center gap-1 px-2 py-1.5 cursor-pointer rounded-md transition-colors text-sm',
            'hover:bg-primary/10',
            isSelected && 'bg-primary/20 text-primary',
            !isSelected && 'text-foreground/80'
          )}
          style={{ paddingLeft: `${level * 12 + 8}px` }}
        >
          {hasChildren ? (
            isExpanded ? <ChevronDown className="h-4 w-4 shrink-0 text-muted-foreground" /> : <ChevronRight className="h-4 w-4 shrink-0 text-muted-foreground" />
          ) : <span className="w-4" />}
          <Icon className={cn('h-4 w-4 shrink-0', getIconColor(node.type))} />
          <span className="truncate">{node.name}</span>
        </div>
      </ContextMenuTrigger>
      <ContextMenuContent className="w-52">
        {node.type === 'folder' && (
          <>
            <ContextMenuItem onClick={() => onAddChild(node)}>
              <FilePlus className="mr-2 h-4 w-4" /> Agregar archivo
            </ContextMenuItem>
            <ContextMenuItem onClick={() => {
              const newFolder: TreeNode = { id: genId(), name: 'nueva-carpeta', type: 'folder', children: [] };
              node.children = node.children || [];
              node.children.push(newFolder);
              setIsExpanded(true);
            }}>
              <FolderPlus className="mr-2 h-4 w-4" /> Agregar carpeta
            </ContextMenuItem>
            <ContextMenuSeparator />
          </>
        )}
        <ContextMenuItem onClick={() => onRename(node)}>
          <Pencil className="mr-2 h-4 w-4" /> Renombrar
        </ContextMenuItem>
        <ContextMenuSeparator />
        <ContextMenuItem onClick={() => onDelete(node)} className="text-red-400">
          <Trash2 className="mr-2 h-4 w-4" /> Eliminar
        </ContextMenuItem>
      </ContextMenuContent>

      {hasChildren && isExpanded && (
        <div>
          {node.children!.map((child) => (
            <TreeItem
              key={child.id}
              node={child}
              level={level + 1}
              onSelect={onSelect}
              selectedId={selectedId}
              onRename={onRename}
              onAddChild={onAddChild}
              onDelete={onDelete}
              tree={[]}
              setTree={() => {}}
            />
          ))}
        </div>
      )}
    </ContextMenu>
  );
}

export function FunctionTree({ onSelectNode, selectedNodeId }: FunctionTreeProps) {
  const [tree, setTree] = useState<TreeNode[]>(() => {
    const saved = localStorage.getItem('ide:tree');
    if (saved) try { return JSON.parse(saved); } catch {}
    return initialTree;
  });
  const [renameTarget, setRenameTarget] = useState<TreeNode | null>(null);
  const [renameValue, setRenameValue] = useState('');

  const saveTree = useCallback((t: TreeNode[]) => {
    setTree(t);
    localStorage.setItem('ide:tree', JSON.stringify(t));
  }, []);

  const handleRename = (node: TreeNode) => {
    setRenameTarget(node);
    setRenameValue(node.name);
  };

  const handleRenameConfirm = () => {
    if (!renameTarget || !renameValue.trim()) return;
    const t = JSON.parse(JSON.stringify(tree)) as TreeNode[];
    const visit = (nodes: TreeNode[]) => {
      for (const n of nodes) {
        if (n.id === renameTarget.id) { n.name = renameValue.trim(); return; }
        if (n.children) visit(n.children);
      }
    };
    visit(t);
    saveTree(t);
    setRenameTarget(null);
  };

  const handleAddChild = (parent: TreeNode) => {
    const name = prompt('Nombre del archivo (ej: mi-componente):');
    if (!name?.trim()) return;
    const newNode: TreeNode = {
      id: genId(),
      name: name.trim(),
      type: name.includes('.tsx') ? 'component' : 'page',
      path: `components/${name.trim()}`,
    };
    const t = JSON.parse(JSON.stringify(tree)) as TreeNode[];
    const visit = (nodes: TreeNode[]) => {
      for (const n of nodes) {
        if (n.id === parent.id) {
          n.children = n.children || [];
          n.children.push(newNode);
          return;
        }
        if (n.children) visit(n.children);
      }
    };
    visit(t);
    saveTree(t);
  };

  const handleDelete = (node: TreeNode) => {
    if (!confirm(`Eliminar "${node.name}" del arbol?`)) return;
    const t = JSON.parse(JSON.stringify(tree)) as TreeNode[];
    const doRemove = (nodes: TreeNode[]): boolean => {
      for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === node.id) { nodes.splice(i, 1); return true; }
        if (nodes[i].children && doRemove(nodes[i].children!)) return true;
      }
      return false;
    };
    doRemove(t);
    saveTree(t);
  };

  return (
    <>
      <div className="h-full flex flex-col bg-card border-r border-border">
        <div className="p-3 border-b border-border bg-muted/30">
          <h3 className="text-sm font-semibold text-primary flex items-center gap-2">
            <FolderOpen className="h-4 w-4" />
            Explorador de Funciones
          </h3>
          <p className="text-[10px] text-muted-foreground mt-1">Clic derecho para editar</p>
        </div>
        <ScrollArea className="flex-1">
          <div className="p-2">
            {tree.map((node) => (
              <TreeItem
                key={node.id}
                node={node}
                level={0}
                onSelect={onSelectNode}
                selectedId={selectedNodeId}
                onRename={handleRename}
                onAddChild={handleAddChild}
                onDelete={handleDelete}
                tree={tree}
                setTree={saveTree}
              />
            ))}
          </div>
        </ScrollArea>
      </div>

      {/* Rename Dialog */}
      <Dialog open={!!renameTarget} onOpenChange={() => setRenameTarget(null)}>
        <DialogContent className="sm:max-w-[400px]">
          <DialogHeader>
            <DialogTitle>Renombrar</DialogTitle>
          </DialogHeader>
          <Input value={renameValue} onChange={(e) => setRenameValue(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter') handleRenameConfirm(); }}
            placeholder="Nuevo nombre" autoFocus />
          <DialogFooter>
            <Button variant="outline" onClick={() => setRenameTarget(null)}>Cancelar</Button>
            <Button onClick={handleRenameConfirm}>Renombrar</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

export { initialTree as systemTree };

components/ide/code-editor.tsx:
'use client';

import { useEffect, useState, useRef, useCallback } from 'react';
import Editor, { Monaco } from '@monaco-editor/react';
import { Loader2, Save, Undo, Redo, Search, Copy, FileCode } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import type { TreeNode } from './function-tree';

interface CodeEditorProps {
  selectedNode: TreeNode | null;
  onCodeChange: (code: string) => void;
  onRequestAIAssist: (code: string, prompt: string) => void;
}

type FileDb = Record<string, string>;

export function CodeEditor({ selectedNode, onCodeChange, onRequestAIAssist }: CodeEditorProps) {
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [originalCode, setOriginalCode] = useState('');
  const [hasChanges, setHasChanges] = useState(false);
  const [fileDb, setFileDb] = useState<FileDb | null>(null);
  const editorRef = useRef<any>(null);

  // Load file database once
  useEffect(() => {
    const base = (window as any).__NEXT_DATA__?.runtimeConfig?.basePath || '/v0-ailoginandpanel';
    fetch(`${base}/file-contents.json`)
      .then(r => r.json())
      .then((db: FileDb) => setFileDb(db))
      .catch(() => {
        setFileDb({});
      });
  }, []);

  // Load code when node is selected
  useEffect(() => {
    if (!selectedNode?.path) {
      setCode('// Selecciona un archivo del arbol de funciones para ver el codigo');
      setOriginalCode('');
      setHasChanges(false);
      return;
    }

    setLoading(true);

    // 1. Try localStorage override (user edits)
    const saved = localStorage.getItem(`ide:${selectedNode.path}`);
    if (saved !== null) {
      setCode(saved);
      setOriginalCode(saved);
      setHasChanges(false);
      setLoading(false);
      return;
    }

    // 2. Try embedded file database
    if (fileDb && fileDb[selectedNode.path]) {
      setCode(fileDb[selectedNode.path]);
      setOriginalCode(fileDb[selectedNode.path]);
      setHasChanges(false);
      setLoading(false);
      return;
    }

    // 3. Try API (works on Vercel / dev mode)
    const loadFromApi = async () => {
      try {
        const response = await fetch(`/api/ide/read-file?path=${encodeURIComponent(selectedNode!.path!)}`);
        if (response.ok) {
          const data = await response.json();
          setCode(data.content);
          setOriginalCode(data.content);
          setHasChanges(false);
          return;
        }
      } catch {}
      // 4. Fallback placeholder
      setCode(`// ${selectedNode!.path}\n// (contenido no disponible en modo estatico)\n//\n// Usa el Asistente IA o las Herramientas para generar codigo`);
      setOriginalCode('');
      setLoading(false);
    };
    loadFromApi();
  }, [selectedNode, fileDb]);

  const handleEditorChange = (value: string | undefined) => {
    const newCode = value || '';
    setCode(newCode);
    setHasChanges(newCode !== originalCode);
    onCodeChange(newCode);
  };

  const handleEditorMount = (editor: any, monaco: Monaco) => {
    editorRef.current = editor;

    monaco.editor.defineTheme('system-dark', {
      base: 'vs-dark',
      inherit: true,
      rules: [
        { token: 'comment', foreground: '6A9955' },
        { token: 'keyword', foreground: '569CD6' },
        { token: 'string', foreground: 'CE9178' },
        { token: 'number', foreground: 'B5CEA8' },
        { token: 'type', foreground: '4EC9B0' },
      ],
      colors: {
        'editor.background': '#0a0a0f',
        'editor.foreground': '#D4D4D4',
        'editorLineNumber.foreground': '#5A5A5A',
        'editorLineNumber.activeForeground': '#00F2FF',
        'editor.selectionBackground': '#00F2FF33',
        'editor.lineHighlightBackground': '#00F2FF0D',
      },
    });

    monaco.editor.setTheme('system-dark');
  };

  const handleSave = () => {
    if (!selectedNode?.path) return;
    localStorage.setItem(`ide:${selectedNode.path}`, code);
    setOriginalCode(code);
    setHasChanges(false);
  };

  const handleUndo = () => editorRef.current?.trigger('keyboard', 'undo', null);
  const handleRedo = () => editorRef.current?.trigger('keyboard', 'redo', null);
  const handleFind = () => editorRef.current?.trigger('keyboard', 'actions.find', null);

  const handleCopy = () => {
    const selection = editorRef.current?.getModel()?.getValueInRange(editorRef.current?.getSelection());
    if (selection) navigator.clipboard.writeText(selection);
  };

  const getLanguage = (path?: string) => {
    if (!path) return 'typescript';
    if (path.endsWith('.tsx')) return 'typescript';
    if (path.endsWith('.ts')) return 'typescript';
    if (path.endsWith('.js')) return 'javascript';
    if (path.endsWith('.jsx')) return 'javascript';
    if (path.endsWith('.json')) return 'json';
    if (path.endsWith('.css')) return 'css';
    if (path.endsWith('.html')) return 'html';
    return 'typescript';
  };

  return (
    <div className="h-full flex flex-col bg-[#0a0a0f]">
      <div className="flex items-center justify-between px-3 py-2 border-b border-border bg-muted/30">
        <div className="flex items-center gap-2">
          <FileCode className="h-4 w-4 text-primary" />
          <span className="text-sm font-medium text-foreground truncate max-w-[300px]">
            {selectedNode?.path || 'Sin archivo seleccionado'}
          </span>
          {hasChanges && (
            <span className="text-xs text-yellow-500 font-medium">(modificado)</span>
          )}
        </div>
        <div className="flex items-center gap-1">
          <Button size="sm" variant="ghost" onClick={handleUndo} className="h-7 w-7 p-0" title="Deshacer"><Undo className="h-4 w-4" /></Button>
          <Button size="sm" variant="ghost" onClick={handleRedo} className="h-7 w-7 p-0" title="Rehacer"><Redo className="h-4 w-4" /></Button>
          <Button size="sm" variant="ghost" onClick={handleFind} className="h-7 w-7 p-0" title="Buscar"><Search className="h-4 w-4" /></Button>
          <Button size="sm" variant="ghost" onClick={handleCopy} className="h-7 w-7 p-0" title="Copiar"><Copy className="h-4 w-4" /></Button>
          <Button
            size="sm"
            variant="default"
            onClick={handleSave}
            disabled={!hasChanges}
            className="h-7 px-2 bg-primary text-primary-foreground"
            title="Guardar (localStorage)"
          >
            {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <><Save className="h-4 w-4 mr-1" /> Guardar</>}
          </Button>
        </div>
      </div>

      <div className="flex-1">
        {loading && !code ? (
          <div className="h-full flex items-center justify-center">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        ) : (
          <Editor
            height="100%"
            language={getLanguage(selectedNode?.path)}
            value={code}
            onChange={handleEditorChange}
            onMount={handleEditorMount}
            options={{
              minimap: { enabled: true },
              fontSize: 14,
              fontFamily: 'JetBrains Mono, Fira Code, monospace',
              lineNumbers: 'on',
              wordWrap: 'on',
              automaticLayout: true,
              scrollBeyondLastLine: false,
              renderLineHighlight: 'all',
              cursorBlinking: 'smooth',
              cursorSmoothCaretAnimation: 'on',
              smoothScrolling: true,
              padding: { top: 16 },
              bracketPairColorization: { enabled: true },
              guides: { bracketPairs: true, indentation: true },
            }}
            loading={
              <div className="h-full flex items-center justify-center bg-[#0a0a0f]">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
              </div>
            }
          />
        )}
      </div>
    </div>
  );
}

components/ide/preview-panel.tsx:
'use client';

import { useState, useEffect } from 'react';
import { RefreshCw, Monitor, Smartphone, Tablet, ExternalLink, Eye } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { cn } from '@/lib/utils';
import type { TreeNode } from './function-tree';

interface PreviewPanelProps {
  selectedNode: TreeNode | null;
  code: string;
}

type DeviceMode = 'desktop' | 'tablet' | 'mobile';

const deviceSizes: Record<DeviceMode, { width: string; label: string }> = {
  desktop: { width: '100%', label: 'Escritorio' },
  tablet: { width: '768px', label: 'Tablet' },
  mobile: { width: '375px', label: 'Movil' },
};

function getBasePath(): string {
  return (window as any).__NEXT_DATA__?.runtimeConfig?.basePath || '/v0-ailoginandpanel';
}

function mapPathToRoute(path: string): string {
  const base = getBasePath();
  if (path.includes('app/page.tsx')) return `${base}/`;
  if (path.includes('app/panel/page.tsx')) return `${base}/panel`;
  if (path.includes('app/panel/welcome')) return `${base}/panel/welcome`;
  if (path.includes('app/panel/rrhh')) return `${base}/panel/rrhh`;
  if (path.includes('app/panel/qa-reports')) return `${base}/panel/qa-reports`;
  if (path.includes('app/panel/it-manager/usuarios')) return `${base}/panel/it-manager/usuarios`;
  if (path.includes('app/panel/it-manager/ide')) return `${base}/panel/it-manager/ide`;
  if (path.includes('app/panel/it-manager')) return `${base}/panel/it-manager`;
  if (path.includes('components/')) return `${base}/`; // components don't have routes
  return `${base}/`;
}

export function PreviewPanel({ selectedNode, code }: PreviewPanelProps) {
  const [deviceMode, setDeviceMode] = useState<DeviceMode>('desktop');
  const [refreshKey, setRefreshKey] = useState(0);
  const [previewUrl, setPreviewUrl] = useState('/');

  // Auto-refresh preview when code changes (debounced 800ms)
  useEffect(() => {
    const t = setTimeout(() => setRefreshKey(prev => prev + 1), 800);
    return () => clearTimeout(t);
  }, [code]);

  useEffect(() => {
    if (!selectedNode?.path) {
      setPreviewUrl(getBasePath() + '/');
      return;
    }
    setPreviewUrl(mapPathToRoute(selectedNode.path));
  }, [selectedNode]);

  const handleRefresh = () => setRefreshKey(prev => prev + 1);
  const handleOpenExternal = () => window.open(previewUrl, '_blank');

  return (
    <div className="h-full flex flex-col bg-card border-l border-border">
      <div className="flex items-center justify-between px-3 py-2 border-b border-border bg-muted/30">
        <div className="flex items-center gap-2">
          <Eye className="h-4 w-4 text-primary" />
          <span className="text-sm font-medium text-foreground">Vista Previa</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="flex items-center gap-0.5 bg-muted rounded-md p-0.5 mr-2">
            <Button size="sm" variant="ghost" onClick={() => setDeviceMode('desktop')}
              className={cn('h-6 w-6 p-0', deviceMode === 'desktop' && 'bg-primary/20 text-primary')} title="Escritorio">
              <Monitor className="h-3.5 w-3.5" />
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setDeviceMode('tablet')}
              className={cn('h-6 w-6 p-0', deviceMode === 'tablet' && 'bg-primary/20 text-primary')} title="Tablet">
              <Tablet className="h-3.5 w-3.5" />
            </Button>
            <Button size="sm" variant="ghost" onClick={() => setDeviceMode('mobile')}
              className={cn('h-6 w-6 p-0', deviceMode === 'mobile' && 'bg-primary/20 text-primary')} title="Movil">
              <Smartphone className="h-3.5 w-3.5" />
            </Button>
          </div>
          <Button size="sm" variant="ghost" onClick={handleRefresh} className="h-7 w-7 p-0" title="Refrescar">
            <RefreshCw className="h-4 w-4" />
          </Button>
          <Button size="sm" variant="ghost" onClick={handleOpenExternal} className="h-7 w-7 p-0" title="Abrir en nueva ventana">
            <ExternalLink className="h-4 w-4" />
          </Button>
        </div>
      </div>

      <div className="px-3 py-2 border-b border-border bg-muted/20">
        <div className="flex items-center gap-2 rounded-md bg-input px-3 py-1.5 text-sm text-muted-foreground">
          <span className="text-green-400">app</span>
          <span>{previewUrl}</span>
        </div>
      </div>

      <div className="flex-1 p-4 bg-muted/10 overflow-auto">
        <div
          className={cn(
            'mx-auto bg-background rounded-lg overflow-hidden shadow-lg border border-border transition-all duration-300',
            deviceMode !== 'desktop' && 'shadow-xl'
          )}
          style={{
            width: deviceSizes[deviceMode].width,
            height: deviceMode === 'desktop' ? '100%' : '600px',
            maxWidth: '100%',
          }}
        >
          {selectedNode ? (
            <iframe
              key={refreshKey}
              src={previewUrl}
              className="w-full h-full border-0"
              title="Vista previa"
              sandbox="allow-scripts allow-same-origin allow-forms"
            />
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-muted-foreground p-8">
              <Eye className="h-16 w-16 mb-4 text-primary/30" />
              <p className="text-center text-lg font-medium">Sin vista previa</p>
              <p className="text-center text-sm mt-2">
                Selecciona un archivo del arbol de funciones para ver la vista previa
              </p>
            </div>
          )}
        </div>
        {deviceMode !== 'desktop' && (
          <p className="text-center text-xs text-muted-foreground mt-2">
            {deviceSizes[deviceMode].label} ({deviceSizes[deviceMode].width})
          </p>
        )}
      </div>
    </div>
  );
}

