  const formatLunchAlarm = (): string => {
    const stored = getStoredLunchTime();
    if (!stored) return '';
    const [h, m] = stored.split(':').map(Number);
    const alarmMin = h * 60 + m - 10;
    return minutesToTime(alarmMin);
