'use client';

import type { UsuarioIT } from '@/lib/firebase';

const KEY = 'currentUser';

export function getStoredUser(): UsuarioIT | null {
  if (typeof window === 'undefined') return null;
  try {
    const raw = sessionStorage.getItem(KEY);
    if (raw) return JSON.parse(raw);
    // fallback: migrar desde localStorage si existe (por si venia de sesion anterior)
    const legacy = localStorage.getItem(KEY);
    if (legacy) {
      const user = JSON.parse(legacy);
      sessionStorage.setItem(KEY, JSON.stringify(user));
      localStorage.removeItem(KEY);
      return user;
    }
    return null;
  } catch {
    return null;
  }
}

export function setStoredUser(user: UsuarioIT) {
  sessionStorage.setItem(KEY, JSON.stringify(user));
}

export function removeStoredUser() {
  sessionStorage.removeItem(KEY);
}

